CREATE TABLE public.orders_pickup_handoffs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), client_id uuid NOT NULL REFERENCES public.clients(id) ON DELETE CASCADE, sale_id uuid NOT NULL REFERENCES public.sales(id) ON DELETE CASCADE, status text NOT NULL DEFAULT 'ready' CHECK (status IN ('ready', 'collected')), ready_at timestamptz NOT NULL DEFAULT now(), ready_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, ready_idempotency_key text NOT NULL, collected_at timestamptz, collected_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, collector_name text, collector_phone_last4 text CHECK (collector_phone_last4 IS NULL OR collector_phone_last4 ~ '^[0-9]{4}$'), collection_idempotency_key text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT orders_pickup_handoffs_client_sale_uniq UNIQUE (client_id, sale_id), CONSTRAINT orders_pickup_handoffs_client_ready_key_uniq UNIQUE (client_id, ready_idempotency_key));
CREATE UNIQUE INDEX orders_pickup_handoffs_client_collection_key_uniq ON public.orders_pickup_handoffs (client_id, collection_idempotency_key) WHERE collection_idempotency_key IS NOT NULL;
CREATE INDEX orders_pickup_handoffs_client_status_idx ON public.orders_pickup_handoffs (client_id, status, ready_at DESC);
CREATE TRIGGER orders_pickup_handoffs_updated_at BEFORE UPDATE ON public.orders_pickup_handoffs FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
